module RefModule(  
    input wire [7:0] data_in,  
    input wire [7:0] key,  
    input wire clk,  
    input wire reset,  
    output reg [7:0] data_out  
);  
  wire [7:0] _tap_data_in = data_in & {8{1'b1}};

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            data_out <= 8'b0;  
        end else begin  
            data_out <= data_in ^ key;  
        end  
    end  
endmodule
